#include <stdio.h>

long long gcd(long long a, long long b){
    while(b){
        long long t=b;
        b=a%b;
        a=t;
    }
    return a;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long A,B; scanf("%lld %lld",&A,&B);
        long long g=gcd(A,B);
        long long l=A/g*B; // safe from overflow within 64‑bit
        printf("%lld %lld\n",g,l);
    }
    return 0;
}

