const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=Number(input[idx++]);
let res=[];
function gcd(a,b){
    while(b!==0){
        const t=b;
        b=a%b;
        a=t;
    }
    return a;
}
